export const handler = (input) => {
  const alerts = [];
  let rating_impact = 'pass';
  if (input.top_1_pct > 0.40) {
    rating_impact = 'substandard';
    alerts.push('top_1_customer_over_40pct');
  } else if (input.top_1_pct > 0.25) {
    rating_impact = 'special_mention';
    alerts.push('top_1_customer_over_25pct');
  }
  if (input.top_5_pct > 0.75) {
    alerts.push('top_5_customers_over_75pct');
  }
  if (input.hhi > 2500) {
    alerts.push('hhi_above_antitrust_threshold');
  }
  let recommendation;
  if (rating_impact === 'substandard') {
    recommendation = 'require_concentration_mitigation_plan_and_credit_committee_approval';
  } else if (rating_impact === 'special_mention' || alerts.length > 0) {
    recommendation = 'document_concentration_risk_and_monitor_quarterly';
  } else {
    recommendation = 'no_action_required';
  }
  return {
    rating_impact: rating_impact,
    alerts: alerts,
    recommendation: recommendation
  };
};
